class PersonalityService:
    """Manages natural personality generation for Momo."""
    
    def __init__(self):
        self.default_key = 'professional_maven'
        self.prompts = PERSONALITY_SYSTEM_PROMPTS

    async def get_personality_prompt(self, personality_id: Optional[int]) -> str:
        if not personality_id:
            return self.prompts[self.default_key]
            
        async with AsyncSessionLocal() as db:
            result = await db.execute(select(PersonalityModeModel).where(PersonalityModeModel.id == personality_id))
            mode = result.scalar_one_or_none()
            if mode:
                # Return the actual system prompt from the dictionary based on name
                return self.prompts.get(mode.name, self.prompts[self.default_key])
        
        return self.prompts[self.default_key]

personality_service = PersonalityService()
